@import url("https://fonts.googleapis.com/css2?family=Instrument+Serif&family=Azeret+Mono:wght@400;500;700&display=swap");

:root {
  color: #1a1a1a;
  background: #f0ece4;
  font-family: "Azeret Mono", monospace;
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

* {
  box-sizing: border-box;
}

html {
  background: #f0ece4;
}

body {
  margin: 0;
  min-width: 320px;
  background: #f0ece4;
  color: #1a1a1a;
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  opacity: 0.035;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
}

button,
input,
textarea,
select {
  font: inherit;
}

#root {
  min-height: 100vh;
}

.app-shell {
  position: relative;
  z-index: 1;
  min-height: 100vh;
  padding: var(--space-md, 1.5rem);
  background:
    radial-gradient(circle at top left, rgba(230, 51, 18, 0.06), transparent 32%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.26), rgba(255, 255, 255, 0)),
    var(--color-bg, #f0ece4);
  color: var(--color-ink, #1a1a1a);
}

.site-header {
  display: grid;
  grid-template-columns: auto 1fr;
  align-items: end;
  gap: var(--space-sm, 1rem) var(--space-lg, 2rem);
  padding: var(--space-sm, 1rem) 0 var(--space-md, 1.5rem);
  border-bottom: var(--border-strong, 2px) solid var(--color-line, #211d1a);
}

.brand-lockup {
  display: grid;
  gap: 0.35rem;
}

.brand-tagline,
.section-label,
.frame-kicker,
.signal-index,
.stat-card dt {
  margin: 0;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.24em;
  text-transform: uppercase;
}

.brand-tagline,
.section-label,
.frame-kicker,
.stat-card dt {
  color: var(--color-muted, #8d857b);
}

.brand-wordmark,
h2 {
  margin: 0;
  font-family: var(--font-display, "Instrument Serif", serif);
  font-weight: 400;
  line-height: 0.95;
}

.brand-wordmark {
  font-size: clamp(2.75rem, 5vw, 4rem);
}

.menu-toggle {
  display: none;
  align-self: center;
  justify-self: end;
  border: var(--border-strong, 2px) solid var(--color-line, #211d1a);
  background: transparent;
  color: var(--color-ink, #1a1a1a);
  padding: 0.7rem 1rem;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  cursor: pointer;
  transition:
    background var(--duration-fast, 160ms) ease,
    color var(--duration-fast, 160ms) ease;
}

.menu-toggle:hover {
  background: var(--color-line, #211d1a);
  color: var(--color-bg, #f0ece4);
}

.header-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-md, 1.5rem);
  margin-left: auto;
}

.nav-cluster {
  display: flex;
  align-items: stretch;
}

.nav-button {
  border: var(--border-hairline, 1px) solid var(--color-line, #211d1a);
  border-right: 0;
  background: transparent;
  color: var(--color-ink, #1a1a1a);
  padding: 0.8rem 1.4rem;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  cursor: pointer;
  transition:
    background var(--duration-fast, 160ms) ease,
    color var(--duration-fast, 160ms) ease;
}

.nav-button:last-child {
  border-right: var(--border-hairline, 1px) solid var(--color-line, #211d1a);
}

.nav-button:hover,
.nav-button:focus-visible,
.wallet-button:hover,
.wallet-button:focus-visible {
  background: var(--color-line, #211d1a);
  color: var(--color-bg, #f0ece4);
  outline: none;
}

.header-utility {
  display: flex;
  align-items: center;
  gap: var(--space-sm, 1rem);
}

.live-pill {
  display: inline-flex;
  align-items: center;
  border: var(--border-strong, 2px) solid var(--color-accent, #e63312);
  padding: 0.45rem 0.8rem;
  color: var(--color-accent, #e63312);
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  white-space: nowrap;
}

.wallet-button {
  border: var(--border-strong, 2px) solid var(--color-line, #211d1a);
  background: var(--color-line, #211d1a);
  color: var(--color-bg, #f0ece4);
  padding: 0.9rem 1.25rem;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  cursor: pointer;
  transition:
    background var(--duration-fast, 160ms) ease,
    color var(--duration-fast, 160ms) ease,
    border-color var(--duration-fast, 160ms) ease;
}

.shell-main {
  display: grid;
  gap: var(--space-md, 1.5rem);
  padding: var(--space-md, 1.5rem) 0 0;
}

.frame {
  border: var(--border-strong, 2px) solid var(--color-line, #211d1a);
  background: rgba(247, 242, 234, 0.84);
  backdrop-filter: blur(2px);
}

.frame-hero {
  padding: var(--space-lg, 2rem);
}

.frame-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-sm, 1rem);
  padding-bottom: var(--space-md, 1.5rem);
  border-bottom: var(--border-hairline, 1px) solid rgba(33, 29, 26, 0.24);
}

.frame-badges {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 0.6rem;
}

.frame-badge {
  display: inline-flex;
  align-items: center;
  padding: 0.45rem 0.7rem;
  background: rgba(33, 29, 26, 0.06);
  border: var(--border-hairline, 1px) solid rgba(33, 29, 26, 0.16);
  font-size: 0.68rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.frame-badge-accent {
  border-color: rgba(230, 51, 18, 0.42);
  color: var(--color-accent, #e63312);
}

.hero-layout {
  display: grid;
  grid-template-columns: minmax(0, 1.18fr) minmax(18rem, 0.82fr);
  gap: var(--space-lg, 2rem);
  padding-top: var(--space-lg, 2rem);
}

.hero-copy {
  display: grid;
  gap: var(--space-md, 1.5rem);
}

h2 {
  max-width: 11ch;
  font-size: clamp(2.8rem, 6vw, 5rem);
}

.hero-body {
  max-width: 58ch;
  margin: 0;
  color: var(--color-muted-strong, #5c564f);
  font-size: 0.94rem;
  line-height: 1.8;
}

.signal-list {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.8rem;
}

.signal-card {
  display: grid;
  gap: 0.8rem;
  min-height: 11.5rem;
  padding: 1rem;
  background: rgba(233, 223, 208, 0.5);
  border: var(--border-hairline, 1px) solid rgba(33, 29, 26, 0.18);
}

.signal-index {
  color: var(--color-accent, #e63312);
}

.signal-card p {
  margin: 0;
  color: var(--color-muted-strong, #5c564f);
  font-size: 0.78rem;
  line-height: 1.75;
}

.viewport-panel {
  display: grid;
  gap: var(--space-md, 1.5rem);
  padding: 1rem;
  background: linear-gradient(180deg, rgba(22, 19, 17, 0.96), rgba(22, 19, 17, 0.92));
  color: #f0ece4;
}

.viewport-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

