.grid-preview {
  position: relative;
  min-height: 24rem;
  overflow: hidden;
  border: var(--border-hairline, 1px) solid rgba(240, 236, 228, 0.16);
  background:
    linear-gradient(rgba(240, 236, 228, 0.08) 1px, transparent 1px),
    linear-gradient(90deg, rgba(240, 236, 228, 0.08) 1px, transparent 1px),
    radial-gradient(circle at center, rgba(230, 51, 18, 0.12), transparent 42%),
    #12100f;
  background-size: 1.4rem 1.4rem, 1.4rem 1.4rem, auto, auto;
  cursor: crosshair;
}

.grid-preview::after {
  content: "";
  position: absolute;
  inset: 0;
  background:
    radial-gradient(circle at center, rgba(255, 255, 255, 0.06), transparent 55%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.02), transparent);
}

.grid-preview-orbit {
  position: absolute;
  display: grid;
  place-items: center;
  border-radius: 999px;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.grid-preview-orbit-primary {
  top: 4rem;
  left: 4rem;
  width: 8rem;
  height: 8rem;
  border: 2px solid rgba(240, 236, 228, 0.9);
  background: rgba(240, 236, 228, 0.08);
}

.grid-preview-orbit-secondary {
  right: 3rem;
  bottom: 3rem;
  width: 5.75rem;
  height: 5.75rem;
  border: 2px dashed rgba(240, 236, 228, 0.5);
  color: rgba(240, 236, 228, 0.76);
}

.grid-preview-line {
  position: absolute;
  top: 50%;
  left: 5.8rem;
  width: calc(100% - 12rem);
  height: 1px;
  border-top: 1px dashed rgba(240, 236, 228, 0.38);
  transform: translateY(-50%);
}

.grid-preview-reticle {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 8rem;
  height: 8rem;
  border: 1px solid rgba(230, 51, 18, 0.52);
  transform: translate(-50%, -50%);
}

.grid-preview-reticle::before,
.grid-preview-reticle::after {
  content: "";
  position: absolute;
  background: rgba(230, 51, 18, 0.52);
}

.grid-preview-reticle::before {
  top: 50%;
  left: -2rem;
  width: calc(100% + 4rem);
  height: 1px;
  transform: translateY(-50%);
}

.grid-preview-reticle::after {
  top: -2rem;
  left: 50%;
  width: 1px;
  height: calc(100% + 4rem);
  transform: translateX(-50%);
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.6rem;
  margin: 0;
}

.stat-card {
  display: grid;
  gap: 0.5rem;
  margin: 0;
  padding: 0.85rem;
  border: var(--border-hairline, 1px) solid rgba(240, 236, 228, 0.12);
  background: rgba(240, 236, 228, 0.04);
}

.stat-card dd {
  margin: 0;
  font-size: 0.86rem;
  line-height: 1.5;
}

.frame-panels {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.info-panel {
  padding: var(--space-lg, 2rem);
}

.info-panel + .info-panel {
  border-left: var(--border-hairline, 1px) solid rgba(33, 29, 26, 0.18);
}

.sequence-list,
.notes-list {
  display: grid;
  gap: 0.85rem;
  margin: 1rem 0 0;
  padding-left: 1.15rem;
  color: var(--color-muted-strong, #5c564f);
  font-size: 0.84rem;
  line-height: 1.8;
}

@media (max-width: 1080px) {
  .hero-layout,
  .frame-panels,
  .signal-list,
  .stats-grid {
    grid-template-columns: 1fr;
  }

  h2 {
    max-width: 12ch;
  }
}

@media (max-width: 720px) {
  .app-shell {
    padding: var(--space-sm, 1rem);
  }

  .site-header {
    grid-template-columns: 1fr auto;
    align-items: start;
  }

  .menu-toggle {
    display: inline-flex;
  }

  .header-actions {
    display: none;
    grid-column: 1 / -1;
    width: 100%;
    margin: 0;
    padding-top: var(--space-sm, 1rem);
    border-top: var(--border-hairline, 1px) solid rgba(33, 29, 26, 0.18);
  }

  .header-actions.is-open {
    display: grid;
    gap: var(--space-sm, 1rem);
  }

  .nav-cluster,
  .header-utility {
    display: grid;
    width: 100%;
  }

  .nav-button {
    width: 100%;
    border-right: var(--border-hairline, 1px) solid var(--color-line, #211d1a);
    text-align: left;
  }

  .nav-button + .nav-button {
    border-top: 0;
  }

  .wallet-button {
    width: 100%;
  }

  .frame-hero,
  .info-panel {
    padding: var(--space-md, 1.5rem);
  }

  .frame-header,
  .viewport-meta {
    align-items: start;
    flex-direction: column;
  }

  h2 {
    max-width: none;
    font-size: clamp(2.4rem, 12vw, 3.8rem);
  }

  .grid-preview {
    min-height: 19rem;
  }

  .grid-preview-orbit-primary {
    top: 2.5rem;
    left: 1.5rem;
  }

  .grid-preview-orbit-secondary {
    right: 1.5rem;
    bottom: 2rem;
  }
}

{
  "name": "ic-automaton-launchpad",
  "version": "0.1.0",
  "private": true,
  "packageManager": "npm@10.9.0",
  "engines": {
    "node": ">=20.19.0",
    "npm": ">=10"
  },
  "workspaces": [
    "apps/*",
    "packages/*"
  ],
  "scripts": {
    "lint": "npm run lint --workspace @ic-automaton/shared && npm run lint --workspace @ic-automaton/indexer && npm run lint --workspace @ic-automaton/web && npm run lint:factory",
    "lint:factory": "cargo fmt --check -p factory && cargo clippy -p factory --all-targets -- -D warnings",
    "build": "npm run build --workspace @ic-automaton/shared && npm run build --workspace @ic-automaton/indexer && npm run build --workspace @ic-automaton/web",
    "test": "npm run test --workspace @ic-automaton/shared && npm run test --workspace @ic-automaton/indexer && npm run test --workspace @ic-automaton/web",
    "test:factory": "cargo test -p factory"
  },
  "devDependencies": {
