                  className={`icon-btn${copyLabel === "OK" ? " copied" : ""}`}
                  disabled={automaton?.ethAddress === null || automaton === null}
                  onClick={() => {
                    void copyAddress();
                  }}
                  type="button"
                >
                  {copyLabel}
                </button>
                <a
                  className="icon-btn"
                  href={automaton?.explorerUrl ?? "#"}
                  rel="noreferrer"
                  target="_blank"
                >
                  SCAN
                </a>
              </div>
            </div>

            <div className="detail-field">
              <div className="lbl">Steward</div>
